'use client'

import { useState } from 'react'
import { CheckCircle2, RefreshCw } from 'lucide-react'
import { format } from 'date-fns'
import type { ContentEpisodePayload, SocialPlatform } from '@/lib/agent/types'
import { getPlatformLabel } from '@/lib/constants/platforms'
import {
  formatFullPackage,
  formatPlatformForCopy,
  getPlatformCopyLabel,
} from '@/lib/content/format-package'
import { CopyButton } from '@/components/shared/CopyButton'
import { DownloadTextButton } from '@/components/shared/DownloadTextButton'
import { RegenerateDialog } from '@/components/studio/RegenerateDialog'

function CopyBlock({
  label,
  content,
  mono = false,
}: {
  label: string
  content: string
  mono?: boolean
}) {
  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between gap-2">
        <p className="text-xs uppercase tracking-widest text-[#71717a]">{label}</p>
        <CopyButton text={content} label="Copy" variant="ghost" iconOnly />
      </div>
      <pre
        className={`max-h-72 overflow-y-auto whitespace-pre-wrap rounded-xl border border-[#27272a] bg-[#09090b] p-4 text-sm text-[#e4e4e7] ${
          mono ? 'font-mono text-xs' : 'font-sans'
        }`}
      >
        {content}
      </pre>
    </div>
  )
}

function SocialPostPanel({
  platform,
  text,
  hashtags,
}: {
  platform: SocialPlatform
  text: string
  hashtags?: string[]
}) {
  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <CopyButton text={text} label={getPlatformCopyLabel(platform)} variant="primary" />
      </div>
      <CopyBlock label="Ready to paste" content={text} />
      {hashtags && hashtags.length > 0 && (
        <div className="flex flex-wrap gap-1.5 items-center">
          {hashtags.map((tag) => (
            <span key={tag} className="text-xs px-2 py-0.5 rounded-full bg-[#27272a] text-[#a1a1aa]">
              #{tag.replace(/^#/, '')}
            </span>
          ))}
          <CopyButton
            text={hashtags.map((h) => (h.startsWith('#') ? h : `#${h}`)).join(' ')}
            label="Copy hashtags"
            variant="ghost"
          />
        </div>
      )}
    </div>
  )
}

function PlatformPanel({
  platform,
  payload,
}: {
  platform: SocialPlatform
  payload: ContentEpisodePayload
}) {
  const copyText = formatPlatformForCopy(platform, payload.content)
  const content = payload.content[platform]
  if (!content || !copyText) return null

  if (platform === 'x' || platform === 'linkedin' || platform === 'facebook') {
    const social = content as NonNullable<typeof payload.content.x>
    return (
      <SocialPostPanel
        platform={platform}
        text={copyText}
        hashtags={social.hashtags}
      />
    )
  }

  if (platform === 'instagram') {
    const ig = content as NonNullable<typeof payload.content.instagram>
    return (
      <div className="space-y-4">
        <CopyButton text={copyText} label={getPlatformCopyLabel(platform)} variant="primary" />
        <CopyBlock label="Caption" content={copyText} />
        {ig.reelScript && (
          <CopyBlock
            label="Reel script"
            content={`${ig.reelScript.hook}\n\n${ig.reelScript.body}\n\n${ig.reelScript.cta}`}
          />
        )}
      </div>
    )
  }

  if (platform === 'tiktok') {
    const tt = content as NonNullable<typeof payload.content.tiktok>
    return (
      <div className="space-y-4">
        <CopyButton text={copyText} label={getPlatformCopyLabel(platform)} variant="primary" />
        <CopyBlock label="Full TikTok package" content={copyText} />
        <CopyBlock label="Caption only" content={tt.caption} />
      </div>
    )
  }

  if (platform === 'youtube_short') {
    const yt = content as NonNullable<typeof payload.content.youtube_short>
    const script = `${yt.script.hook}\n\n${yt.script.body}\n\n${yt.script.cta}`
    return (
      <div className="space-y-4">
        <CopyButton text={copyText} label={getPlatformCopyLabel(platform)} variant="primary" />
        <div>
          <p className="text-xs uppercase tracking-widest text-[#71717a] mb-2">Title options</p>
          <div className="flex flex-wrap gap-2">
            {yt.youtube.titleOptions.map((title) => (
              <span
                key={title}
                className="inline-flex items-center gap-1 text-sm px-3 py-1.5 rounded-lg bg-[#27272a] border border-[#3f3f46]"
              >
                {title}
                <CopyButton text={title} variant="ghost" iconOnly />
              </span>
            ))}
          </div>
        </div>
        <CopyBlock label="Script" content={script} />
        <CopyBlock label="Description" content={yt.youtube.description} />
        <CopyButton text={yt.youtube.tags.join(', ')} label="Copy tags" variant="secondary" />
      </div>
    )
  }

  if (platform === 'youtube_long') {
    const yt = content as NonNullable<typeof payload.content.youtube_long>
    return (
      <div className="space-y-4">
        <CopyButton text={copyText} label={getPlatformCopyLabel(platform)} variant="primary" />
        <CopyBlock label="Full script" content={yt.script} />
        <CopyBlock label="Description" content={yt.youtube.description} />
      </div>
    )
  }

  return <CopyBlock label="Content" content={copyText} />
}

interface ContentPackageViewProps {
  payload: ContentEpisodePayload
  topic: string
  packageId?: string | null
  savedAt?: string | null
  onRegenerate?: (platform: SocialPlatform, feedback: string) => Promise<void>
  isRegenerating?: boolean
}

export function ContentPackageView({
  payload,
  topic,
  packageId,
  savedAt,
  onRegenerate,
  isRegenerating,
}: ContentPackageViewProps) {
  const [activeTab, setActiveTab] = useState<'overview' | SocialPlatform>('overview')
  const [regenerateOpen, setRegenerateOpen] = useState(false)
  const fullPackage = formatFullPackage(topic, payload)

  const tabs: Array<{ id: 'overview' | SocialPlatform; label: string }> = [
    { id: 'overview', label: 'Overview' },
    ...payload.platforms.map((p) => ({
      id: p as 'overview' | SocialPlatform,
      label: getPlatformLabel(p),
    })),
  ]

  return (
    <div className="card overflow-hidden">
      <div className="p-6 border-b border-[#27272a] flex flex-col sm:flex-row sm:items-start sm:justify-between gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <h3 className="font-semibold text-lg">Content package</h3>
            {packageId && (
              <span className="inline-flex items-center gap-1 text-xs text-emerald-400 bg-emerald-500/10 px-2 py-0.5 rounded-full">
                <CheckCircle2 className="w-3 h-3" />
                Saved
              </span>
            )}
          </div>
          <p className="text-sm text-[#71717a] line-clamp-2">{topic}</p>
          {savedAt && (
            <p className="text-[10px] text-[#52525b] mt-1">
              {format(new Date(savedAt), 'MMM d, yyyy · h:mm a')}
            </p>
          )}
        </div>
        <div className="flex flex-wrap gap-2">
          <CopyButton text={fullPackage} label="Copy full package" variant="primary" />
          <DownloadTextButton
            text={fullPackage}
            filename={`tekmarketing-${topic.slice(0, 40).replace(/[^\w\s-]/g, '').trim().replace(/\s+/g, '-') || 'package'}`}
            label="Download .txt"
          />
        </div>
      </div>

      <div className="px-6 pt-4 flex flex-wrap gap-2 border-b border-[#27272a] pb-4">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            type="button"
            onClick={() => setActiveTab(tab.id)}
            className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
              activeTab === tab.id
                ? 'bg-blue-500/15 text-blue-300'
                : 'text-[#71717a] hover:bg-[#27272a] hover:text-[#f4f4f5]'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      <div className="p-6 space-y-6">
        {activeTab !== 'overview' && onRegenerate && (
          <div className="flex justify-end">
            <button
              type="button"
              onClick={() => setRegenerateOpen(true)}
              disabled={isRegenerating}
              className="btn btn-secondary h-9 text-xs"
            >
              <RefreshCw className={`w-3.5 h-3.5 ${isRegenerating ? 'animate-spin' : ''}`} />
              Regenerate with feedback
            </button>
          </div>
        )}

        {activeTab === 'overview' ? (
          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
            <div>
              <p className="text-xs uppercase tracking-widest text-[#71717a] mb-2">Strategy</p>
              <p className="text-sm text-[#a1a1aa] leading-relaxed">{payload.strategyNote}</p>
            </div>
            <div className="p-4 rounded-xl bg-blue-500/5 border border-blue-500/20">
              <p className="text-xs uppercase tracking-widest text-[#71717a] mb-2">Agent reasoning</p>
              <p className="text-sm text-[#a1a1aa] leading-relaxed">{payload.agentReasoning}</p>
            </div>
            <div className="xl:col-span-2">
              <p className="text-xs uppercase tracking-widest text-[#71717a] mb-3">
                Quick copy — one click per platform
              </p>
              <div className="flex flex-wrap gap-2">
                {payload.platforms.map((platform) => {
                  const text = formatPlatformForCopy(platform, payload.content)
                  if (!text) return null
                  return (
                    <CopyButton
                      key={platform}
                      text={text}
                      label={getPlatformCopyLabel(platform)}
                      variant="secondary"
                    />
                  )
                })}
              </div>
            </div>
          </div>
        ) : (
          <PlatformPanel platform={activeTab} payload={payload} />
        )}
      </div>

      {activeTab !== 'overview' && onRegenerate && (
        <RegenerateDialog
          platform={activeTab}
          open={regenerateOpen}
          onClose={() => setRegenerateOpen(false)}
          onRegenerate={(feedback) => onRegenerate(activeTab, feedback)}
        />
      )}
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { formatDistanceToNow } from 'date-fns'
import { ExternalLink, RefreshCw } from 'lucide-react'
import type { SocialPlatform } from '@/lib/agent/types'
import { getPlatformLabel } from '@/lib/constants/platforms'

interface PackageRow {
  id: string
  businessName: string
  topic: string
  platforms: SocialPlatform[]
  createdAt: string
}

export function PackageLibrary() {
  const [packages, setPackages] = useState<PackageRow[]>([])
  const [isLoading, setIsLoading] = useState(true)

  async function load() {
    setIsLoading(true)
    try {
      const res = await fetch('/api/packages?limit=30')
      if (res.ok) {
        const data = await res.json()
        setPackages(data.packages || [])
      }
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    load()
  }, [])

  return (
    <div>
      <div className="flex justify-end mb-4">
        <button onClick={load} className="btn btn-ghost h-9 px-3 text-xs border border-[#27272a]">
          <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {isLoading ? (
        <div className="card p-12 text-center text-[#71717a]">Loading packages...</div>
      ) : packages.length === 0 ? (
        <div className="card p-12 text-center">
          <p className="text-lg font-medium mb-2">No saved packages yet</p>
          <p className="text-sm text-[#71717a] mb-6">
            Generate content from the studio — every package is saved automatically.
          </p>
          <Link href="/content-studio/generate" className="btn btn-primary h-10">
            Go to Generate
          </Link>
        </div>
      ) : (
        <div className="space-y-3">
          {packages.map((pkg) => (
            <div key={pkg.id} className="card p-5 hover:border-[#3f3f46] transition-colors">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">
                  <div className="text-sm text-[#71717a] mb-1">
                    {pkg.businessName} ·{' '}
                    {formatDistanceToNow(new Date(pkg.createdAt), { addSuffix: true })}
                  </div>
                  <div className="font-medium text-[15px] line-clamp-2">{pkg.topic}</div>
                  <div className="flex flex-wrap gap-1.5 mt-2">
                    {pkg.platforms.map((p) => (
                      <span
                        key={p}
                        className="text-[10px] px-2 py-0.5 rounded-full bg-[#27272a] text-[#a1a1aa]"
                      >
                        {getPlatformLabel(p)}
                      </span>
                    ))}
                  </div>
                </div>
                <Link
                  href={`/content-studio/generate?package=${pkg.id}`}
                  className="btn btn-secondary h-8 px-3 text-xs shrink-0"
                >
                  <ExternalLink className="w-3 h-3" />
                  Open &amp; copy
                </Link>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useState } from 'react'
import { Loader2, RefreshCw } from 'lucide-react'
import type { SocialPlatform } from '@/lib/agent/types'
import { getPlatformLabel } from '@/lib/constants/platforms'

interface RegenerateDialogProps {
  platform: SocialPlatform
  open: boolean
  onClose: () => void
  onRegenerate: (feedback: string) => Promise<void>
}

export function RegenerateDialog({
  platform,
  open,
  onClose,
  onRegenerate,
}: RegenerateDialogProps) {
  const [feedback, setFeedback] = useState('')
  const [isLoading, setIsLoading] = useState(false)

  if (!open) return null

  async function handleSubmit() {
    if (!feedback.trim()) return
    setIsLoading(true)
    try {
      await onRegenerate(feedback.trim())
      setFeedback('')
      onClose()
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4"
      onClick={onClose}
    >
      <div
        className="w-full max-w-lg card p-6 shadow-xl"
        onClick={(e) => e.stopPropagation()}
      >
        <h3 className="text-lg font-semibold">Regenerate {getPlatformLabel(platform)}</h3>
        <p className="mt-1 text-sm text-[#71717a]">
          Tell the AI what to change — tone, length, angle, or specifics to add.
        </p>
        <textarea
          className="textarea w-full mt-4 min-h-[100px]"
          value={feedback}
          onChange={(e) => setFeedback(e.target.value)}
          placeholder="e.g. Shorter hook, more professional tone, stronger CTA..."
          disabled={isLoading}
        />
        <div className="mt-4 flex justify-end gap-2">
          <button type="button" onClick={onClose} disabled={isLoading} className="btn btn-secondary h-9">
            Cancel
          </button>
          <button
            type="button"
            onClick={handleSubmit}
            disabled={isLoading || !feedback.trim()}
            className="btn btn-primary h-9"
          >
            {isLoading ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <RefreshCw className="w-4 h-4" />
            )}
            Regenerate
          </button>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useCallback, useEffect, useState } from 'react'
import Link from 'next/link'
import { useSearchParams } from 'next/navigation'
import { Lightbulb, Loader2, Sparkles } from 'lucide-react'
import { toast } from 'sonner'
import type { ContentEpisodePayload, SocialPlatform } from '@/lib/agent/types'
import { PLATFORMS } from '@/lib/constants/platforms'
import { ContentPackageView } from '@/components/studio/ContentPackageView'

interface Business {
  id: string
  companyName: string
  isActive: boolean
}

interface TopicSuggestion {
  topic: string
  angle: string
  whyNow: string
}

interface SavedPackage {
  id: string
  topic: string
  platforms: SocialPlatform[]
  strategyNote: string
  agentReasoning: string
  content: ContentEpisodePayload['content']
  createdAt: string
  businessId: string
}

export function StudioGenerate() {
  const searchParams = useSearchParams()
  const packageParam = searchParams.get('package')

  const [businesses, setBusinesses] = useState<Business[]>([])
  const [brandId, setBrandId] = useState('')
  const [topic, setTopic] = useState('')
  const [platforms, setPlatforms] = useState<SocialPlatform[]>([
    'linkedin',
    'x',
    'instagram',
  ])
  const [activeProvider, setActiveProvider] = useState('xai')
  const [isGenerating, setIsGenerating] = useState(false)
  const [isRecommending, setIsRecommending] = useState(false)
  const [isRegenerating, setIsRegenerating] = useState(false)
  const [suggestions, setSuggestions] = useState<TopicSuggestion[]>([])
  const [result, setResult] = useState<ContentEpisodePayload | null>(null)
  const [packageId, setPackageId] = useState<string | null>(null)
  const [savedAt, setSavedAt] = useState<string | null>(null)

  const loadPackage = useCallback(async (id: string) => {
    const res = await fetch(`/api/packages/${id}`)
    if (!res.ok) return
    const data = await res.json()
    const pkg = data.package as SavedPackage
    setBrandId(pkg.businessId)
    setTopic(pkg.topic)
    setPlatforms(pkg.platforms)
    setPackageId(pkg.id)
    setSavedAt(pkg.createdAt)
    setResult({
      platforms: pkg.platforms,
      strategyNote: pkg.strategyNote,
      agentReasoning: pkg.agentReasoning,
      content: pkg.content,
    })
    setSuggestions([])
  }, [])

  useEffect(() => {
    fetch('/api/businesses')
      .then((r) => r.json())
      .then((d) => {
        const list = d.businesses || []
        setBusinesses(list)
        if (!packageParam) {
          const active = list.find((b: Business) => b.isActive) || list[0]
          if (active) setBrandId(active.id)
        }
      })
    fetch('/api/settings')
      .then((r) => r.json())
      .then((d) => setActiveProvider(d.activeProvider || 'xai'))
  }, [packageParam])

  useEffect(() => {
    if (packageParam) loadPackage(packageParam)
  }, [packageParam, loadPackage])

  function togglePlatform(id: SocialPlatform) {
    setPlatforms((prev) =>
      prev.includes(id) ? prev.filter((p) => p !== id) : [...prev, id]
    )
  }

  async function handleRecommendTopics() {
    if (!brandId) {
      toast.error('Select a business first')
      return
    }
    setIsRecommending(true)
    setSuggestions([])
    try {
      const res = await fetch('/api/generate/recommend-topic', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ brandContextId: brandId, provider: activeProvider }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error || 'Failed to suggest topics')
      setSuggestions(data.suggestions || [])
      toast.success(`${data.suggestions?.length || 0} topic ideas ready`)
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Could not suggest topics')
    } finally {
      setIsRecommending(false)
    }
  }

  function applySuggestion(s: TopicSuggestion) {
    setTopic(s.topic)
    setSuggestions([])
    toast.success('Topic applied — edit if needed, then generate')
  }

  async function handleGenerate() {
    if (!brandId) {
      toast.error('Select a business first')
      return
    }
    if (!topic.trim()) {
      toast.error('Enter a topic or use Suggest topics')
      return
    }
    if (platforms.length === 0) {
      toast.error('Select at least one platform')
      return
    }

    setIsGenerating(true)
    setResult(null)
    setPackageId(null)
    setSavedAt(null)
    try {
      const res = await fetch('/api/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          brandContextId: brandId,
          topic: topic.trim(),
          platforms,
          provider: activeProvider,
        }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error || 'Generation failed')

      setResult({
        platforms: data.package.platforms,
        strategyNote: data.package.strategyNote,
        agentReasoning: data.package.agentReasoning,
        content: data.package.content,
      })
      setPackageId(data.package.id)
      setSavedAt(data.package.createdAt)
      window.history.replaceState(
        null,
        '',
        `/content-studio/generate?package=${data.package.id}`
      )
      toast.success('Package generated and saved')
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Generation failed')
    } finally {
      setIsGenerating(false)
    }
  }

  async function handleRegenerate(platform: SocialPlatform, feedback: string) {
    if (!packageId) return
    setIsRegenerating(true)
    try {
      const res = await fetch('/api/generate/regenerate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ packageId, platform, feedback, provider: activeProvider }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error || 'Regeneration failed')
      setResult({
        platforms: data.package.platforms,
        strategyNote: data.package.strategyNote,
        agentReasoning: data.package.agentReasoning,
        content: data.package.content,
      })
      toast.success(`${platform} content updated`)
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Regeneration failed')
    } finally {
      setIsRegenerating(false)
    }
  }

  return (
    <div className="space-y-8">
      <div className="card p-4 border-blue-500/20 bg-blue-500/5 text-sm text-[#a1a1aa]">
        <strong className="text-[#f4f4f5]">Workflow:</strong> Pick a topic → select platforms →
        generate → copy each post and paste into your social apps. Packages auto-save to{' '}
        <Link href="/content-studio/packages" className="text-blue-400 hover:underline">
          your library
        </Link>
        .
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="card p-5 space-y-3">
          <div className="text-xs uppercase tracking-widest text-[#71717a]">1 · Business</div>
          <select
            value={brandId}
            onChange={(e) => {
              setBrandId(e.target.value)
              setSuggestions([])
            }}
            className="input w-full"
          >
            {businesses.length === 0 && <option value="">No businesses — create one first</option>}
            {businesses.map((b) => (
              <option key={b.id} value={b.id}>
                {b.companyName}
              </option>
            ))}
          </select>
        </div>

        <div className="card p-5 space-y-3 lg:col-span-2">
          <div className="flex items-center justify-between gap-2">
            <div className="text-xs uppercase tracking-widest text-[#71717a]">2 · Topic</div>
            <button
              type="button"
              onClick={handleRecommendTopics}
              disabled={isRecommending || !brandId}
              className="btn btn-secondary h-8 px-3 text-xs disabled:opacity-50"
            >
              {isRecommending ? (
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
              ) : (
                <Lightbulb className="w-3.5 h-3.5" />
              )}
              Suggest topics
            </button>
          </div>
          <textarea
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="What should this content package be about? Or click Suggest topics for AI ideas based on your brand."
            className="input w-full min-h-[88px]"
          />
        </div>
      </div>

      {suggestions.length > 0 && (
        <div className="card p-5 space-y-3">
          <p className="text-xs uppercase tracking-widest text-[#71717a]">Suggested topics</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {suggestions.map((s, i) => (
              <button
                key={i}
                type="button"
                onClick={() => applySuggestion(s)}
                className="text-left p-4 rounded-xl border border-[#27272a] hover:border-blue-500/40 hover:bg-blue-500/5 transition-colors"
              >
                <div className="text-sm font-medium text-[#f4f4f5] mb-1">{s.angle}</div>
                <div className="text-xs text-[#a1a1aa] line-clamp-2 mb-2">{s.topic}</div>
                <div className="text-[10px] text-[#52525b]">{s.whyNow}</div>
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="card p-5 space-y-4">
        <div className="text-xs uppercase tracking-widest text-[#71717a]">3 · Platforms</div>
        <p className="text-xs text-[#52525b] -mt-2">
          Select where you plan to post — content is formatted for copy-paste into each app.
        </p>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          {PLATFORMS.map((p) => {
            const selected = platforms.includes(p.id)
            return (
              <button
                key={p.id}
                type="button"
                onClick={() => togglePlatform(p.id)}
                className={`p-3 rounded-xl border text-left transition-colors ${
                  selected
                    ? 'border-blue-500/50 bg-blue-500/5'
                    : 'border-[#27272a] hover:border-[#3f3f46]'
                }`}
              >
                <div className="text-sm font-medium">{p.shortLabel}</div>
                <div className="text-[10px] text-[#71717a] mt-0.5 line-clamp-2">{p.description}</div>
              </button>
            )
          })}
        </div>
      </div>

      <button
        onClick={handleGenerate}
        disabled={isGenerating}
        className="btn btn-primary h-11 px-8"
      >
        {isGenerating ? (
          <Loader2 className="w-4 h-4 animate-spin" />
        ) : (
          <Sparkles className="w-4 h-4" />
        )}
        Generate &amp; save package
      </button>

      {isGenerating && (
        <div className="card p-12 text-center text-[#71717a]">
          Building your multi-platform package… usually 30–60 seconds.
        </div>
      )}

      {result && (
        <ContentPackageView
          payload={result}
          topic={topic}
          packageId={packageId}
          savedAt={savedAt}
          onRegenerate={packageId ? handleRegenerate : undefined}
          isRegenerating={isRegenerating}
        />
      )}
    </div>
  )
}

